/* Text Move */

.text-move {
  display: -webkit-box;
  display: -ms-flexbox;
  display: flex;
  -webkit-text-fill-color: transparent;
  -webkit-text-stroke: 2px #6e6e6e;
  -ms-flex-negative: 0;
  flex-shrink: 0;
  -webkit-box-align: center;
  -ms-flex-align: center;
  align-items: center;
  padding: 0 6px;
  -webkit-animation: slide-left 20s linear infinite;
  animation: slide-left 20s linear infinite;
}

.text-move-area {
  overflow: hidden;
  display: flex;
  align-items: center;
}

.text-move {
  margin: 0;
  font-size: 120px;
  line-height: 1;
